def decode_b64(b64_str):
    import re
    # Remove any non-base64 characters first
    b64_str = re.sub(r'[^A-Za-z0-9+/]', '', b64_str)
    
    # Keep padding until it works
    while True:
        try:
            return base64.b64decode(b64_str + '=' * (4 - len(b64_str) % 4))
        except Exception:
            b64_str += 'A'

# 1. College Image (JPEG)
college_img_b64 = ""
with open(os.path.join(img_dir, "college_main.jpg"), "wb") as f:
    f.write(decode_b64(college_img_b64))

# 2. College Logo (PNG)
college_logo_b64 = ""
with open(os.path.join(img_dir, "vvit_logo.png"), "wb") as f:
    f.write(decode_b64(college_logo_b64))

# 3. Third image from URL
url = "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSmPXit2JuLJ6TMaDa65iHZJOF_KMcBNjUPSQ&s"
